mapper.select:
select distinct br.book_id
from tb_borrow_record br
where br.reader_id = #{readerId}

select b.book_id, b.book_name, b.author, b.press, count(*) as score
from tb_borrow_record br1
join tb_borrow_record br2 on br1.reader_id = br2.reader_id
join tb_book b on br2.book_id = b.book_id
where br1.book_id = #{bookId}
  and br2.book_id != #{bookId}
  and br2.book_id not in (
      select distinct book_id from tb_borrow_record where reader_id = #{readerId}
  )
group by br2.book_id, b.book_name, b.author, b.press
order by score desc
limit 6

select date(br.borrow_date) as date, count(*) as count
from tb_borrow_record br


        AND br.reader_id = #{readerId}


        AND br.borrow_date >= #{params.beginTime}


group by date(br.borrow_date)
order by date(br.borrow_date) asc

select br.borrow_id, br.reader_id, br.book_id, br.borrow_date, br.due_date,
       br.return_date, br.status, br.renew_count, br.fine_amount,
       br.create_by, br.create_time, br.update_by, br.update_time, br.remark,
       r.name as reader_name, b.book_name as book_name
from tb_borrow_record br
left join tb_reader r on br.reader_id = r.reader_id
left join tb_book b on br.book_id = b.book_id


        AND br.borrow_id = #{borrowId}


        AND br.reader_id = #{readerId}


        AND br.book_id = #{bookId}


        AND br.status = #{status}


        AND r.name like concat('%', #{readerName}, '%')


        AND b.book_name like concat('%', #{bookName}, '%')


        AND br.borrow_date >= #{params.beginTime}


        AND br.borrow_date <= #{params.endTime}


order by br.borrow_date desc


where br.reader_id = #{readerId}
  and br.status in ('borrowing', 'overdue')
order by br.due_date asc


where br.book_id = #{bookId}
  and br.status in ('borrowing', 'overdue')
limit 1

mapper.update:
update tb_borrow_record
return_date = #{returnDate}, status = #{status}, renew_count = #{renewCount}, due_date = #{dueDate}, fine_amount = #{fineAmount}, update_by = #{updateBy}, remark = #{remark}, update_time = sysdate()
where borrow_id = #{borrowId}
